#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
   int val;
   struct Node* left;
   struct Node* right;
   struct Node* next;
} Node;

Node* connect(Node* root) {
   if (root == NULL) return NULL;

   Node* leftmost = root;
   while (leftmost->left) {
      Node* head = leftmost;
      while (head) {
         head->left->next = head->right;

         if (head->next) {
            head->right->next = head->next->left;
         }

         head = head->next;
      }
      leftmost = leftmost->left;
   }

   return root;
}

